content:
) { format!("{}", parent_sc.span_id()) } else { String::new() }
            };

            if let (Some(tid), Some(sid)) = (trace_id, span_id) {
                let fields = OtelFields {
                    trace_id: tid,
                    span_id: sid,
                    parent_span_id,
                };
                drop(extensions);
                span.extensions_mut().insert(fields);
            }
        }
    }
}
